def generate_jwt_token(address: str) -> str:
    """Generate a JWT token for an authenticated address."""
    payload = {
        'sub': address,
        'iat': datetime.utcnow(),
        'exp': datetime.utcnow() + timedelta(hours=JWT_EXPIRY_HOURS),
        'jti': str(uuid.uuid4()),
        'type': 'access'
    }
    return jwt.encode(payload, SECRET_KEY, algorithm='HS256')


def verify_jwt_token(token: str) -> Dict[str, Any]:
    """Verify and decode a JWT token."""
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=['HS256'])
        return payload
    except jwt.ExpiredSignatureError:
        raise AuthenticationError("Token has expired.")
    except jwt.InvalidTokenError as e:
        raise AuthenticationError(f"Invalid token: {str(e)}")


def cleanup_expired_challenges():
    """Remove expired challenges from the store."""
    now = time.time()
    expired = [
        key for key, val in challenge_store.items()
        if now - val['created_at'] > CHALLENGE_EXPIRY_SECONDS
    ]
    for key in expired:
        del challenge_store[key]
    if expired:
        logger.info(f"Cleaned up {len(expired)} expired challenges.")


def require_auth(f):
    """Decorator to require JWT authentication on endpoints."""
    from functools import wraps

    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')
        if not auth_header.startswith('Bearer '):
            return jsonify({
                'success': False,
                'error': 'Missing or invalid Authorization header. Use: Bearer <token>'
            }), 401

        token = auth_header[7:]
        try:
            payload = verify_jwt_token(token)
            g.current_user = payload['sub']
            g.token_payload = payload
        except AuthenticationError as e:
            return jsonify({'success': False, 'error': e.message}), e.status_code

        return f(*args, **kwargs)

    return decorated


